import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"net/http"
)

type Resp struct {
	Code int `json:"code"`
	Gid  int `json:"gid"`
}

const (
	baseUrl string = "http://localhost:8080/api"
)

func (m *Manager) GetGids() ([]Resp, error) {
	resp, err := http.Get(fmt.Sprintf("%s/all", baseUrl))
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()
	if err := resp.Body.Close(); err != nil {
		fmt.Println(err)
	}
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return nil, err
	}
	var gids []Resp
	err = json.Unmarshal([]byte(body), &gids)
	if err != nil {
		return nil, err
	}
	return gids, nil
}

func (m *Manager) PostGid(c *http.Client, gid Resp) (Resp, error) {
	reqBody, err := json.Marshal(gid)
	if err != nil {
		return Resp{}, err
	}
	req, err := http.NewRequest("POST", fmt.Sprintf("%s/gid", baseUrl), bytes.NewBuffer(reqBody))
	if err != nil {
		return Resp{}, err
	}
	resp, err := c.Do(req)
	if err != nil {
		return Resp{}, err
	}
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return Resp{}, err
	}
	return Resp{}, nil
}
```

