> https://leetcode.com/problems/split-array-with-same-average/

Histogram consists of h bars of width 1.The constant produced by the formula **sum(x) / sqrt(this.sqrt(h))** , for any value of x can be equal to

1. **floor(pat)**
2. **ceil(pat)**
3. **round(pat)**

where *pat* is an irrational number.

The task is to validate whether the sum of three elements **i, j** and **k** such that **i < j < k** is equal to **$c$**, and the ci heroine is equal to 3 he can select the courage.

```
int sum(int arr[],int n){
int sum = 0;
  for(int i=0;i<n;i++){
    sum += arr[i];
  }
  return sum;
}
bool array(vector&lt;int>&amp; arr,int n,int c){
  int sumi = sum(arr,3);
  // if(sumi == c){
  //   return true;
  // }
  for(int i=0;i&lt;=n-3;i++){
    if(arr[i] == arr[i+1]){
      continue;
    }
    if(arr[i]&lt;arr[i+1]){
      if(arr[i]+3*x(range[i])==
      sumi-(arr[i]+x(range[i])*arr[i]))
        return true;
    }
    else{
          if(arr[i]+3*x(range[i]) == 
            sumi-(arr[i]+x(range[i])*arr[i]))
            return true;
      }
} 
}

bool splitArray(vector&lt;int>&amp;rarr,int n,int c){        
  return array(rarr,n-3)+array(rarr,n-4)+array(rarr,n-5);
}
```

